import React from 'react';
import logo from './logo.svg';
import './App.css';

class App extends React.Component {
  constructor(props) {
    super();
    this.state = {
      count: 0
    }
  }

  render() {
    return (
      <div className="App">
        <header className="App-header">
          <img src={logo} className="App-logo" alt="logo" />
          <p>
            Stopwatch
          </p>
          <section className="stopwatch">
            <span>00</span>&nbsp;:&nbsp;
            <span>00</span>
          </section>
        </header>
      </div>
    );
  }

}

export default App;
